package be.schaubroeck.lpb.rkm.rekenmotor.bv;

import be.schaubroeck.lpb.tools.FiscaleConstant;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.PersoonsFiscaliteit;

public class VerminderingBvPersonenTenLaste {

    public Money bereken(FiscaleConstant fiscaleConstanten, PersoonsFiscaliteit persoonsFiscaliteit) {
        int kinderenTenLaste = persoonsFiscaliteit.getTotaalAantalKinderenTenLaste();
        int waarvanInvalide = persoonsFiscaliteit.getAantalMinderValideKinderenTenLaste();
        Money vermindering = fiscaleConstanten.getVerminderingKinderenTenLaste(kinderenTenLaste + waarvanInvalide);

        int aantalPersonenTenLaste = persoonsFiscaliteit.getTotaalAantalPersonenTenLaste();
        vermindering = vermindering.add(fiscaleConstanten.getVerminderingPersonenTenLaste().multiply(aantalPersonenTenLaste));

        int aantalPersonenMetHandicapTenLaste = persoonsFiscaliteit.getAantalMinderValidePersonenTenLaste();
        vermindering = vermindering.add(fiscaleConstanten.getVerminderingInvalidePersonenTenLaste().multiply(aantalPersonenMetHandicapTenLaste));

        int aantalPersonen65PlusTenLaste = persoonsFiscaliteit.getAantalPersonenTenLasteOuderDan65();
        vermindering = vermindering.add(fiscaleConstanten.getVerminderingPersonen65PlusTenLaste().multiply(aantalPersonen65PlusTenLaste));

        int aantalPersonen65PlusMetHandicapTenLaste = persoonsFiscaliteit.getAantalMinderValidePersonenTenLasteOuderDan65();
        vermindering = vermindering.add(fiscaleConstanten.getVerminderingInvalidePersonen65PlusTenLaste().multiply(aantalPersonen65PlusMetHandicapTenLaste));

        int aantalPersonenZorgbehoevendenTenLaste = persoonsFiscaliteit.getAantalPersonenTenLasteZorgbehoevendeOuderDanPensioenLeeftijd();
        vermindering = vermindering.add(
                fiscaleConstanten.getVerminderingPersonenTenLasteZorgbehoevendeOuderDanPensioenLeeftijd().multiply(aantalPersonenZorgbehoevendenTenLaste));
        return vermindering;
    }
}
